// src/pages/PostInternship.jsx
import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";

export default function PostInternship() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    title: "",
    company: "",
    location: "",
    description: "",
    stipend: "",
    duration: "",
    lastDate: "",
  });

  const handleChange = (e) => {
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const token = localStorage.getItem("token");
      await axios.post(
        "/api/internships",
        formData,
        {
          headers: { Authorization: `Bearer ${token}` },
        }
      );
      alert("Internship posted successfully!");
      navigate("/internship");
    } catch (error) {
      alert("Error posting internship.");
      console.error(error);
    }
  };

  return (
    <div className="max-w-xl mx-auto mt-8 p-6 bg-white shadow-md rounded">
      <h2 className="text-xl font-bold mb-4">Post New Internship</h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        {["title", "company", "location", "description", "stipend", "duration", "lastDate"].map((field) => (
          <input
            key={field}
            type="text"
            name={field}
            placeholder={field[0].toUpperCase() + field.slice(1)}
            value={formData[field]}
            onChange={handleChange}
            className="w-full border px-3 py-2 rounded"
            required
          />
        ))}
        <button type="submit" className="bg-green-600 text-white px-4 py-2 rounded">
          Post Internship
        </button>
      </form>
    </div>
  );
}
